// Monta mensagem de acordo com o status
const order = $json.body.order;
const status = order.status;
const name = order.customerName || 'Cliente';
const orderNum = order.orderNumber;

const messages = {
  Confirmed: `✅ *Pedido ${orderNum} confirmado!*\n\nOlá ${name}! Seu pedido foi confirmado e está sendo preparado.`,
  Preparing: `👨‍🍳 *Pedido ${orderNum} em preparação!*\n\nSeu pedido está sendo preparado.`,
  ReadyForPickup: `🏪 *Pedido ${orderNum} pronto para retirada!*\n\nSeu pedido está pronto! Você pode retirá-lo em nossa loja.`,
  OutForDelivery: `🚚 *Pedido ${orderNum} saiu para entrega!*\n\nSeu pedido está a caminho! Em breve chegará até você.`,
  Delivered: `✅ *Pedido ${orderNum} entregue!*\n\nSeu pedido foi entregue. Obrigado pela compra! 😊`,
  Cancelled: `❌ *Pedido ${orderNum} cancelado.*\n\n${order.cancellationReason ? 'Motivo: ' + order.cancellationReason : 'Seu pedido foi cancelado.'}\n\nPrecisa de ajuda? Digite "atendente".`
};

const message = messages[status] || `📦 Status do pedido ${orderNum}: ${status}`;
return { message, order };
